static int check_policy(X509_STORE_CTX *ct)
{
    int ret;
    ret = X509_policy_check(&ct->tree, &ct->eplicit_policy, ct->chain,
                            ct->param->policies, ct->param->flags);
    if (ret == 0) {
        X509err(X509_F_CHECK_POLICY, ERR_R_MALLOC_FAILURE);
        return 0;
    }
    /* Invalid or inconsistent etensions */
    if (ret == -1) {
        /*
         * Locate certificates with bad etensions and notify callback.
         */
        X509 *;
        int i;
        for (i = 1; i < sk_X509_num(ct->chain); i++) {
             = sk_X509_value(ct->chain, i);
            if (!(->e_flags & EXFLAG_INVALID_POLICY))
                continue;
            ct->current_cert = ;
            ct->error = X509_V_ERR_INVALID_POLICY_EXTENSION;
            ret = ct->verify_cb(0, ct);
        }
        return 1;
    }
    if (ret == -2) {
        ct->current_cert = NULL;
        ct->error = X509_V_ERR_NO_EXPLICIT_POLICY;
        return ct->verify_cb(0, ct);
    }

    if (ct->param->flags & X509_V_FLAG_NOTIFY_POLICY) {
        ct->current_cert = NULL;
        ct->error = X509_V_OK;
        if (!ct->verify_cb(2, ct))
            return 0;
    }

    return 1;
}

static char *TracePSClippath(const unsigned char *blob,size_t length)
{
  char
    *path,
    *message;

  MagickBooleanType
    in_subpath;

  PointInfo
    first[3],
    last[3],
    point[3];

  ssize_t
    i,
    ;

  ssize_t
    knot_count,
    selector,
    y;

  path=AcquireString((char *) NULL);
  if (path == (char *) NULL)
    return((char *) NULL);
  message=AcquireString((char *) NULL);
  (void) FormatLocaleString(message,MagickPathEtent,"/ClipImage\n");
  (void) ConcatenateString(&path,message);
  (void) FormatLocaleString(message,MagickPathEtent,"{\n");
  (void) ConcatenateString(&path,message);
  (void) FormatLocaleString(message,MagickPathEtent,
    "  /c {curveto} bind def\n");
  (void) ConcatenateString(&path,message);
  (void) FormatLocaleString(message,MagickPathEtent,
    "  /l {lineto} bind def\n");
  (void) ConcatenateString(&path,message);
  (void) FormatLocaleString(message,MagickPathEtent,
    "  /m {moveto} bind def\n");
  (void) ConcatenateString(&path,message);
  (void) FormatLocaleString(message,MagickPathEtent,
    "  /v {currentpoint 6 2 roll curveto} bind def\n");
  (void) ConcatenateString(&path,message);
  (void) FormatLocaleString(message,MagickPathEtent,
    "  /y {2 copy curveto} bind def\n");
  (void) ConcatenateString(&path,message);
  (void) FormatLocaleString(message,MagickPathEtent,
    "  /z {closepath} bind def\n");
  (void) ConcatenateString(&path,message);
  (void) FormatLocaleString(message,MagickPathEtent,"  newpath\n");
  (void) ConcatenateString(&path,message);
  /*
    The clipping path format is defined in "Adobe Photoshop File Formats
    Specification" version 6.0 downloadable from adobe.com.
  */
  (void) memset(point,0,sizeof(point));
  (void) memset(first,0,sizeof(first));
  (void) memset(last,0,sizeof(last));
  knot_count=0;
  in_subpath=MagickFalse;
  while (length > 0)
  {
    selector=(ssize_t) ReadPropertyMSBShort(&blob,&length);
    switch (selector)
    {
      case 0:
      case 3:
      {
        if (knot_count != 0)
          {
            blob+=24;
            length-=MagickMin(24,(ssize_t) length);
            break;
          }
        /*
          Epected subpath length record.
        */
        knot_count=(ssize_t) ReadPropertyMSBShort(&blob,&length);
        blob+=22;
        length-=MagickMin(22,(ssize_t) length);
        break;
      }
      case 1:
      case 2:
      case 4:
      case 5:
      {
        if (knot_count == 0)
          {
            /*
              Unepected subpath knot
            */
            blob+=24;
            length-=MagickMin(24,(ssize_t) length);
            break;
          }
        /*
          Add sub-path knot
        */
        for (i=0; i < 3; i++)
        {
          y=(ssize_t) ReadPropertyMSBLong(&blob,&length);
          =(ssize_t) ReadPropertyMSBLong(&blob,&length);
          point[i].=(double) /4096.0/4096.0;
          point[i].y=1.0-(double) y/4096.0/4096.0;
        }
        if (in_subpath == MagickFalse)
          {
            (void) FormatLocaleString(message,MagickPathEtent,"  %g %g m\n",
              point[1].,point[1].y);
            for (i=0; i < 3; i++)
            {
              first[i]=point[i];
              last[i]=point[i];
            }
          }
        else
          {
            /*
              Handle special cases when Bezier curves are used to describe
              corners and straight lines.
            */
            if ((last[1]. == last[2].) && (last[1].y == last[2].y) &&
                (point[0]. == point[1].) && (point[0].y == point[1].y))
              (void) FormatLocaleString(message,MagickPathEtent,
                "  %g %g l\n",point[1].,point[1].y);
            else
              if ((last[1]. == last[2].) && (last[1].y == last[2].y))
                (void) FormatLocaleString(message,MagickPathEtent,
                  "  %g %g %g %g v\n",point[0].,point[0].y,
                  point[1].,point[1].y);
              else
                if ((point[0]. == point[1].) && (point[0].y == point[1].y))
                  (void) FormatLocaleString(message,MagickPathEtent,
                    "  %g %g %g %g y\n",last[2].,last[2].y,
                    point[1].,point[1].y);
                else
                  (void) FormatLocaleString(message,MagickPathEtent,
                    "  %g %g %g %g %g %g c\n",last[2].,
                    last[2].y,point[0].,point[0].y,point[1].,point[1].y);
            for (i=0; i < 3; i++)
              last[i]=point[i];
          }
        (void) ConcatenateString(&path,message);
        in_subpath=MagickTrue;
        knot_count--;
        /*
          Close the subpath if there are no more knots.
        */
        if (knot_count == 0)
          {
            /*
              Same special handling as above ecept we compare to the
              first point in the path and close the path.
            */
            if ((last[1]. == last[2].) && (last[1].y == last[2].y) &&
                (first[0]. == first[1].) && (first[0].y == first[1].y))
              (void) FormatLocaleString(message,MagickPathEtent,
                "  %g %g l z\n",first[1].,first[1].y);
            else
              if ((last[1]. == last[2].) && (last[1].y == last[2].y))
                (void) FormatLocaleString(message,MagickPathEtent,
                  "  %g %g %g %g v z\n",first[0].,first[0].y,
                  first[1].,first[1].y);
              else
                if ((first[0]. == first[1].) && (first[0].y == first[1].y))
                  (void) FormatLocaleString(message,MagickPathEtent,
                    "  %g %g %g %g y z\n",last[2].,last[2].y,
                    first[1].,first[1].y);
                else
                  (void) FormatLocaleString(message,MagickPathEtent,
                    "  %g %g %g %g %g %g c z\n",last[2].,
                    last[2].y,first[0].,first[0].y,first[1].,first[1].y);
            (void) ConcatenateString(&path,message);
            in_subpath=MagickFalse;
          }
        break;
      }
      case 6:
      case 7:
      case 8:
      default:
      {
        blob+=24;
        length-=MagickMin(24,(ssize_t) length);
        break;
      }
    }
  }
  /*
    Returns an empty PS path if the path has no knots.
  */
  (void) FormatLocaleString(message,MagickPathEtent,"  eoclip\n");
  (void) ConcatenateString(&path,message);
  (void) FormatLocaleString(message,MagickPathEtent,"} bind def");
  (void) ConcatenateString(&path,message);
  message=DestroyString(message);
  return(path);
}

