void SetOutput(OpKernelContet* contet, int ragged_rank,
               const vector<INDEX_TYPE>& output_inde,
               Tensor* output_tensor) override {
  // Note: it's ok to use OP_REQUIRES_OK (rather than TF_RETURN_IF_ERROR)
  // in this function, but only because it's the last thing we do before
  // returning from Compute().

  if (output_tensor->NumElements() == 0) return;

  const auto& values_tensor = contet->input(kValueInputInde);
  const VALUE_TYPE* values_base = values_tensor.flat<VALUE_TYPE>().data();
  const auto& default_value_tensor = contet->input(kDefaultValueInputInde);
  VALUE_TYPE* output_base = output_tensor->flat<VALUE_TYPE>().data();

  TensorShape element_shape = output_tensor->shape();
  element_shape.RemoveDimRange(0, ragged_rank + 1);
  int value_element_size = element_shape.num_elements();
  size_t output_inde_size = output_inde.size();

  // Broadcast the default value to value_element_size.  (We can skip this
  // if default_value_tensor.NumElements() == 1, since we use std::fill
  // when that's true.)
  const VALUE_TYPE* default_value =
      default_value_tensor.flat<VALUE_TYPE>().data();
  Tensor bcast_default;  // Temporary tensor for result of broadcast
  if (default_value_tensor.NumElements() != value_element_size &&
      default_value_tensor.NumElements() != 1) {
    const auto& src_shape = default_value_tensor.shape();
    BCast bcast(BCast::FromShape(src_shape), BCast::FromShape(element_shape),
                /*fewer_dims_optimization=*/true);
    // Note: bcast should always be valid, since we rejected any incompatible
    // shapes when we called ValidateDefaultValueShape().
    OP_REQUIRES(contet, bcast.IsValid(),
                errors::InvalidArgument("Error broadcasting default_value"));
    OP_REQUIRES_OK(contet,
                   contet->allocate_temp(default_value_tensor.dtype(),
                                          element_shape, &bcast_default));
    const CPUDevice& device = contet->eigen_device<CPUDevice>();
    functor::BroadcastTo<CPUDevice, VALUE_TYPE>()(
        device, contet, bcast_default, element_shape, default_value_tensor,
        src_shape, bcast);
    default_value = bcast_default.flat<VALUE_TYPE>().data();
  }

  // Loop through the output_inde vector, finding contiguous regions that
  // should be copied.  Once we find the end of a contiguous region, copy it
  // and add any necessary padding (with default_value).
  INDEX_TYPE src_start = 0;  // Start of contiguous region (in values)
  INDEX_TYPE dst_start = 0;  // Destination for contiguous region (in output)
  INDEX_TYPE dst_end = 0;    // Destination for contiguous region (in output)
  for (int src_i = 0; src_i <= output_inde_size; ++src_i) {
    // dst_i is the destination where the value at src_i should be copied.
    INDEX_TYPE dst_i = src_i < output_inde_size ? output_inde[src_i] : -1;

    // If we're still in a contiguous region, then update dst_end go to the
    // net src_i.
    if (dst_i == dst_end) {
      ++dst_end;
      continue;
    }

    // We found the end of contiguous region.  This can be because we found
    // a gap (dst_i > dst_end), or a source value that shouldn't be copied
    // because it's out-of-bounds (dst_i == -1), or the end of the tensor
    // (dst_i = -1).
    if (dst_start < dst_end) {
      // Copy the contiguous region.
      const VALUE_TYPE* src = values_base + src_start * value_element_size;
      VALUE_TYPE* dst = output_base + dst_start * value_element_size;
      INDEX_TYPE nvals = (dst_end - dst_start) * value_element_size;
      copy_array<VALUE_TYPE, INDEX_TYPE>(dst, src, nvals);
    }

    // Add any necessary padding (w/ default_value).
    if (src_i >= output_inde_size) {
      // We reached the end of values: pad to the end of output.
      size_t output_size = output_tensor->NumElements();
      dst_i = output_size / value_element_size;
    }
    if (dst_i > dst_end) {
      if (default_value_tensor.NumElements() == 1) {
        std::fill(output_base + dst_end * value_element_size,
                  output_base + dst_i * value_element_size, *default_value);
        dst_end = dst_i;
      } else {
        while (dst_i > dst_end) {
          VALUE_TYPE* dst = output_base + dst_end * value_element_size;
          copy_array<VALUE_TYPE, INDEX_TYPE>(dst, default_value,
                                             value_element_size);
          ++dst_end;
        }
      }
    }

    // Update indices.
    if (dst_i < 0) {
      // src_i should be skipped -- leave it out of the contiguous region.
      src_start = src_i + 1;
      dst_start = dst_end;
    } else {
      // src_i should be copied -- include it in the contiguous region.
      src_start = src_i;
      dst_start = dst_end;
      dst_end = dst_start + 1;
    }
  }
}

CMS_RecipientInfo *CMS_add0_recipient_key(CMS_ContentInfo *cms, int nid,
                                          unsigned char *key, size_t keylen,
                                          unsigned char *id, size_t idlen,
                                          ASN1_GENERALIZEDTIME *date,
                                          ASN1_OBJECT *otherTypeId,
                                          ASN1_TYPE *otherType)
{
    CMS_RecipientInfo *ri = NULL;
    CMS_EnvelopedData *env;
    CMS_KEKRecipientInfo *kekri;
    env = cms_get0_enveloped(cms);
    if (!env)
        goto err;

    if (nid == NID_undef) {
        switch (keylen) {
        case 16:
            nid = NID_id_aes128_wrap;
            break;

        case 24:
            nid = NID_id_aes192_wrap;
            break;

        case 32:
            nid = NID_id_aes256_wrap;
            break;

        default:
            CMSerr(CMS_F_CMS_ADD0_RECIPIENT_KEY, CMS_R_INVALID_KEY_LENGTH);
            goto err;
        }

    } else {

        size_t ep_keylen = aes_wrap_keylen(nid);

        if (!ep_keylen) {
            CMSerr(CMS_F_CMS_ADD0_RECIPIENT_KEY,
                   CMS_R_UNSUPPORTED_KEK_ALGORITHM);
            goto err;
        }

        if (keylen != ep_keylen) {
            CMSerr(CMS_F_CMS_ADD0_RECIPIENT_KEY, CMS_R_INVALID_KEY_LENGTH);
            goto err;
        }

    }

    /* Initialize recipient info */
    ri = M_ASN1_new_of(CMS_RecipientInfo);
    if (!ri)
        goto merr;

    ri->d.kekri = M_ASN1_new_of(CMS_KEKRecipientInfo);
    if (!ri->d.kekri)
        goto merr;
    ri->type = CMS_RECIPINFO_KEK;

    kekri = ri->d.kekri;

    if (otherTypeId) {
        kekri->kekid->other = M_ASN1_new_of(CMS_OtherKeyAttribute);
        if (kekri->kekid->other == NULL)
            goto merr;
    }

    if (!sk_CMS_RecipientInfo_push(env->recipientInfos, ri))
        goto merr;

    /* After this point no calls can fail */

    kekri->version = 4;

    kekri->key = key;
    kekri->keylen = keylen;

    ASN1_STRING_set0(kekri->kekid->keyIdentifier, id, idlen);

    kekri->kekid->date = date;

    if (kekri->kekid->other) {
        kekri->kekid->other->keyAttrId = otherTypeId;
        kekri->kekid->other->keyAttr = otherType;
    }

    X509_ALGOR_set0(kekri->keyEncryptionAlgorithm,
                    OBJ_nid2obj(nid), V_ASN1_UNDEF, NULL);

    return ri;

 merr:
    CMSerr(CMS_F_CMS_ADD0_RECIPIENT_KEY, ERR_R_MALLOC_FAILURE);
 err:
    M_ASN1_free_of(ri, CMS_RecipientInfo);
    return NULL;

}

check_suggestions(
    suginfo_T	*su,
    garray_T	*gap)		    // either su_ga or su_sga
{
    suggest_T   *stp;
    int		i;
    char_u	longword[MAXWLEN + 1];
    int		len;
    hlf_T	attr;

    if (gap->ga_len == 0)
	return;
    stp = &SUG(*gap, 0);
    for (i = gap->ga_len - 1; i >= 0; --i)
    {
	// Need to append what follows to check for "the the".
	vim_strncpy(longword, stp[i].st_word, MAXWLEN);
	len = stp[i].st_wordlen;
	vim_strncpy(longword + len, su->su_badptr + stp[i].st_orglen,
							       MAXWLEN - len);
	attr = HLF_COUNT;
	(void)spell_check(curwin, longword, &attr, NULL, FALSE);
	if (attr != HLF_COUNT)
	{
	    // Remove this entry.
	    vim_free(stp[i].st_word);
	    --gap->ga_len;
	    if (i < gap->ga_len)
		mch_memmove(stp + i, stp + i + 1,
				       sizeof(suggest_T) * (gap->ga_len - i));
	}
    }
}

static ssize_t bearssl_send(struct Curl_easy *data, int sockinde,
                            const void *buf, size_t len, CURLcode *err)
{
  struct connectdata *conn = data->conn;
  struct ssl_connect_data *connssl = &conn->ssl[sockinde];
  struct ssl_backend_data *backend = connssl->backend;
  unsigned char *app;
  size_t applen;

  for(;;) {
    *err = bearssl_run_until(data, conn, sockinde, BR_SSL_SENDAPP);
    if (*err != CURLE_OK)
      return -1;
    app = br_ssl_engine_sendapp_buf(&backend->ct.eng, &applen);
    if(!app) {
      failf(data, "SSL: connection closed during write");
      *err = CURLE_SEND_ERROR;
      return -1;
    }
    if(backend->pending_write) {
      applen = backend->pending_write;
      backend->pending_write = 0;
      return applen;
    }
    if(applen > len)
      applen = len;
    memcpy(app, buf, applen);
    br_ssl_engine_sendapp_ack(&backend->ct.eng, applen);
    br_ssl_engine_flush(&backend->ct.eng, 0);
    backend->pending_write = applen;
  }
}

TEE_Result syscall_asymm_verify(unsigned long state,
			const struct utee_attribute *usr_params,
			size_t num_params, const void *data, size_t data_len,
			const void *sig, size_t sig_len)
{
	TEE_Result res;
	struct tee_cryp_state *cs;
	struct tee_ta_session *sess;
	struct tee_obj *o;
	size_t hash_size;
	int salt_len = 0;
	TEE_Attribute *params = NULL;
	uint32_t hash_algo;
	struct user_ta_ct *utc;

	res = tee_ta_get_current_session(&sess);
	if (res != TEE_SUCCESS)
		return res;
	utc = to_user_ta_ct(sess->ct);

	res = tee_svc_cryp_get_state(sess, tee_svc_uref_to_vaddr(state), &cs);
	if (res != TEE_SUCCESS)
		return res;

	if (cs->mode != TEE_MODE_VERIFY)
		return TEE_ERROR_BAD_PARAMETERS;

	res = tee_mmu_check_access_rights(utc,
					  TEE_MEMORY_ACCESS_READ |
					  TEE_MEMORY_ACCESS_ANY_OWNER,
					  (uaddr_t)data, data_len);
	if (res != TEE_SUCCESS)
		return res;

	res = tee_mmu_check_access_rights(utc,
					  TEE_MEMORY_ACCESS_READ |
					  TEE_MEMORY_ACCESS_ANY_OWNER,
					  (uaddr_t)sig, sig_len);
	if (res != TEE_SUCCESS)
		return res;

	size_t alloc_size = 0;

	if (MUL_OVERFLOW(sizeof(TEE_Attribute), num_params, &alloc_size))
		return TEE_ERROR_OVERFLOW;

	params = malloc(alloc_size);
	if (!params)
		return TEE_ERROR_OUT_OF_MEMORY;
	res = copy_in_attrs(utc, usr_params, num_params, params);
	if (res != TEE_SUCCESS)
		goto out;

	res = tee_obj_get(utc, cs->key1, &o);
	if (res != TEE_SUCCESS)
		goto out;
	if ((o->info.handleFlags & TEE_HANDLE_FLAG_INITIALIZED) == 0) {
		res = TEE_ERROR_BAD_PARAMETERS;
		goto out;
	}

	switch (TEE_ALG_GET_MAIN_ALG(cs->algo)) {
	case TEE_MAIN_ALGO_RSA:
		if (cs->algo != TEE_ALG_RSASSA_PKCS1_V1_5) {
			hash_algo = TEE_DIGEST_HASH_TO_ALGO(cs->algo);
			res = tee_hash_get_digest_size(hash_algo, &hash_size);
			if (res != TEE_SUCCESS)
				break;
			if (data_len != hash_size) {
				res = TEE_ERROR_BAD_PARAMETERS;
				break;
			}
			salt_len = pkcs1_get_salt_len(params, num_params,
						      hash_size);
		}
		res = crypto_acipher_rsassa_verify(cs->algo, o->attr, salt_len,
						   data, data_len, sig,
						   sig_len);
		break;

	case TEE_MAIN_ALGO_DSA:
		hash_algo = TEE_DIGEST_HASH_TO_ALGO(cs->algo);
		res = tee_hash_get_digest_size(hash_algo, &hash_size);
		if (res != TEE_SUCCESS)
			break;
		/*
		 * Depending on the DSA algorithm (NIST), the digital signature
		 * output size may be truncated to the size of a key pair
		 * (Q prime size). Q prime size must be less or equal than the
		 * hash output length of the hash algorithm involved.
		 */
		if (data_len > hash_size) {
			res = TEE_ERROR_BAD_PARAMETERS;
			break;
		}
		res = crypto_acipher_dsa_verify(cs->algo, o->attr, data,
						data_len, sig, sig_len);
		break;

	case TEE_MAIN_ALGO_ECDSA:
		res = crypto_acipher_ecc_verify(cs->algo, o->attr, data,
						data_len, sig, sig_len);
		break;

	default:
		res = TEE_ERROR_NOT_SUPPORTED;
	}

out:
	free_wipe(params);
	return res;
}

mesalink_close(struct Curl_easy *data, struct connectdata *conn, int sockinde)
{
