static void print_ml_row(FILE *ml_file, const char *row_name,
                          MYSQL_RES *tableRes, MYSQL_ROW *row,
                          const char *str_create)
{
  uint i;
  my_bool body_found MY_ATTRIBUTE((unused)) = 0;
  char *create_stmt_ptr= NULL;
  ulong create_stmt_len= 0;
  MYSQL_FIELD *field;
  ulong *lengths= mysql_fetch_lengths(tableRes);

  fprintf(ml_file, "\t\t<%s", row_name);
  check_io(ml_file);
  mysql_field_seek(tableRes, 0);
  for (i= 0; (field= mysql_fetch_field(tableRes)); i++)
  {
    if ((*row)[i])
    {
      /* For 'create' statements, dump using CDATA. */
      if ((str_create) && (strcmp(str_create, field->name) == 0))
      {
        create_stmt_ptr= (*row)[i];
        create_stmt_len= lengths[i];
        body_found= 1;
      }
      else
      {
        fputc(' ', ml_file);
        print_quoted_ml(ml_file, field->name, field->name_length, 1);
        fputs("=\"", ml_file);
        print_quoted_ml(ml_file, (*row)[i], lengths[i], 0);
        fputc('"', ml_file);
        check_io(ml_file);
      }
    }
  }

  if (create_stmt_len)
  {
    DBUG_ASSERT(body_found);
    fputs(">\n", ml_file);
    print_ml_cdata(ml_file, create_stmt_ptr, create_stmt_len);
    fprintf(ml_file, "\t\t</%s>\n", row_name);
  }
  else
    fputs(" />\n", ml_file);

  check_io(ml_file);
}

