		return ret;
	}
	return NULL;
}

int CMS_decrypt_set1_key(CMS_ContentInfo *cms,
                         unsigned char *key, size_t keylen,
                         const unsigned char *id, size_t idlen)
{
    STACK_OF(CMS_RecipientInfo) *ris;
    CMS_RecipientInfo *ri;
    int i, r;
    ris = CMS_get0_RecipientInfos(cms);
    for (i = 0; i < sk_CMS_RecipientInfo_num(ris); i++) {
        ri = sk_CMS_RecipientInfo_value(ris, i);
        if (CMS_RecipientInfo_type(ri) != CMS_RECIPINFO_KEK)
            continue;

        /*
         * If we have an id try matching RecipientInfo otherwise try them
         * all.
         */
        if (!id || (CMS_RecipientInfo_kekri_id_cmp(ri, id, idlen) == 0)) {
            CMS_RecipientInfo_set0_key(ri, key, keylen);
            r = CMS_RecipientInfo_decrypt(cms, ri);
            CMS_RecipientInfo_set0_key(ri, NULL, 0);
            if (r > 0)
                return 1;
            if (id) {
                CMSerr(CMS_F_CMS_DECRYPT_SET1_KEY, CMS_R_DECRYPT_ERROR);
                return 0;
            }
            ERR_clear_error();
        }
    }

    CMSerr(CMS_F_CMS_DECRYPT_SET1_KEY, CMS_R_NO_MATCHING_RECIPIENT);
    return 0;

}

static int chacha20_poly1305_cipher(EVP_CIPHER_CTX *ct, unsigned char *out,
                                    const unsigned char *in, size_t len)
{
    EVP_CHACHA_AEAD_CTX *act = aead_data(ct);
    size_t rem, plen = act->tls_payload_length;

    if (!act->mac_inited) {
#  if !defined(OPENSSL_SMALL_FOOTPRINT)
        if (plen != NO_TLS_PAYLOAD_LENGTH && out != NULL)
            return chacha20_poly1305_tls_cipher(ct, out, in, len);
#  endif
        act->key.counter[0] = 0;
        ChaCha20_ctr32(act->key.buf, zero, CHACHA_BLK_SIZE,
                       act->key.key.d, act->key.counter);
        Poly1305_Init(POLY1305_ct(act), act->key.buf);
        act->key.counter[0] = 1;
        act->key.partial_len = 0;
        act->len.aad = act->len.tet = 0;
        act->mac_inited = 1;
        if (plen != NO_TLS_PAYLOAD_LENGTH) {
            Poly1305_Update(POLY1305_ct(act), act->tls_aad,
                            EVP_AEAD_TLS1_AAD_LEN);
            act->len.aad = EVP_AEAD_TLS1_AAD_LEN;
            act->aad = 1;
        }
    }

    if (in) {                                   /* aad or tet */
        if (out == NULL) {                      /* aad */
            Poly1305_Update(POLY1305_ct(act), in, len);
            act->len.aad += len;
            act->aad = 1;
            return len;
        } else {                                /* plain- or ciphertet */
            if (act->aad) {                    /* wrap up aad */
                if ((rem = (size_t)act->len.aad % POLY1305_BLOCK_SIZE))
                    Poly1305_Update(POLY1305_ct(act), zero,
                                    POLY1305_BLOCK_SIZE - rem);
                act->aad = 0;
            }

            act->tls_payload_length = NO_TLS_PAYLOAD_LENGTH;
            if (plen == NO_TLS_PAYLOAD_LENGTH)
                plen = len;
            else if (len != plen + POLY1305_BLOCK_SIZE)
                return -1;

            if (ct->encrypt) {                 /* plaintet */
                chacha_cipher(ct, out, in, plen);
                Poly1305_Update(POLY1305_ct(act), out, plen);
                in += plen;
                out += plen;
                act->len.tet += plen;
            } else {                            /* ciphertet */
                Poly1305_Update(POLY1305_ct(act), in, plen);
                chacha_cipher(ct, out, in, plen);
                in += plen;
                out += plen;
                act->len.tet += plen;
            }
        }
    }
    if (in == NULL                              /* eplicit final */
        || plen != len) {                       /* or tls mode */
        const union {
            long one;
            char little;
        } is_endian = { 1 };
        unsigned char temp[POLY1305_BLOCK_SIZE];

        if (act->aad) {                        /* wrap up aad */
            if ((rem = (size_t)act->len.aad % POLY1305_BLOCK_SIZE))
                Poly1305_Update(POLY1305_ct(act), zero,
                                POLY1305_BLOCK_SIZE - rem);
            act->aad = 0;
        }

        if ((rem = (size_t)act->len.tet % POLY1305_BLOCK_SIZE))
            Poly1305_Update(POLY1305_ct(act), zero,
                            POLY1305_BLOCK_SIZE - rem);

        if (is_endian.little) {
            Poly1305_Update(POLY1305_ct(act),
                            (unsigned char *)&act->len, POLY1305_BLOCK_SIZE);
        } else {
            temp[0]  = (unsigned char)(act->len.aad);
            temp[1]  = (unsigned char)(act->len.aad>>8);
            temp[2]  = (unsigned char)(act->len.aad>>16);
            temp[3]  = (unsigned char)(act->len.aad>>24);
            temp[4]  = (unsigned char)(act->len.aad>>32);
            temp[5]  = (unsigned char)(act->len.aad>>40);
            temp[6]  = (unsigned char)(act->len.aad>>48);
            temp[7]  = (unsigned char)(act->len.aad>>56);

            temp[8]  = (unsigned char)(act->len.tet);
            temp[9]  = (unsigned char)(act->len.tet>>8);
            temp[10] = (unsigned char)(act->len.tet>>16);
            temp[11] = (unsigned char)(act->len.tet>>24);
            temp[12] = (unsigned char)(act->len.tet>>32);
            temp[13] = (unsigned char)(act->len.tet>>40);
            temp[14] = (unsigned char)(act->len.tet>>48);
            temp[15] = (unsigned char)(act->len.tet>>56);

            Poly1305_Update(POLY1305_ct(act), temp, POLY1305_BLOCK_SIZE);
        }
        Poly1305_Final(POLY1305_ct(act), ct->encrypt ? act->tag
                                                        : temp);
        act->mac_inited = 0;

        if (in != NULL && len != plen) {        /* tls mode */
            if (ct->encrypt) {
                memcpy(out, act->tag, POLY1305_BLOCK_SIZE);
            } else {
                if (CRYPTO_memcmp(temp, in, POLY1305_BLOCK_SIZE)) {
                    memset(out - plen, 0, plen);
                    return -1;
                }
            }
        }
        else if (!ct->encrypt) {
            if (CRYPTO_memcmp(temp, act->tag, act->tag_len))
                return -1;
        }
    }
    return len;
}

static inline void shift_rfc5988_val(php_http_buffer_t *buf, zval *zv, const char *vss, size_t vsl, unsigned flags TSRMLS_DC)
{
	zval *tmp = php_http_zsep(1, IS_STRING, zv);

	quote_string(tmp, 1 TSRMLS_CC);
	php_http_buffer_append(buf, vss, vsl);
	php_http_buffer_append(buf, Z_STRVAL_P(tmp), Z_STRLEN_P(tmp));

	zval_ptr_dtor(&tmp);
}

